// src/lib/workflow/service.ts
// 
// NOTE: The old Lab and LabWorkflow tables are not in the Supabase schema.
// Workflow logic now uses in-memory definitions only (from definitions.ts).
// The state could be stored in project metadata or a future workflow table.
// For now, this is a stub that maintains the interface for callers.

import { prisma } from '@/lib/prisma'
import { getLabDefinition, LabDefinition } from './definitions'

export interface VirtualWorkflow {
    id: string
    projectId: string
    labNumber: number
    currentStep: number
    totalSteps: number
    status: 'IN_PROGRESS' | 'COMPLETED' | 'PAUSED'
    completedSteps: string[]
    definition: LabDefinition
}

export class WorkflowService {

    /**
     * Get active workflow for a project.
     * Since LabWorkflow table doesn't exist in Supabase, we return null.
     * TODO: Implement workflow state storage (project metadata or new table).
     */
    static async getActiveWorkflow(_projectId: string): Promise<VirtualWorkflow | null> {
        // No workflow table in current schema
        // Future: Could store workflow state in project metadata or create a workflow table
        return null
    }

    /**
     * Start a workflow for a project.
     * Currently a no-op since Lab/LabWorkflow tables don't exist.
     */
    static async startWorkflow(projectId: string, labNumber: number): Promise<VirtualWorkflow> {
        const project = await prisma.projects.findUnique({ where: { id: projectId } })
        if (!project) throw new Error('Project not found')

        const definition = getLabDefinition(labNumber)

        // Gate check for Lab 2
        if (labNumber === 2) {
            if (project.score < 50) {
                throw new Error(`Score insuffisant (${project.score}/50) pour accéder au Lab 2`)
            }
        }

        // Return a virtual workflow object (not persisted)
        return {
            id: `workflow_${projectId}_lab${labNumber}`,
            projectId,
            labNumber,
            currentStep: 0,
            totalSteps: definition.steps.length,
            status: 'IN_PROGRESS' as const,
            completedSteps: [],
            definition,
        }
    }

    /**
     * Check gate requirements for a lab.
     */
    static async checkGate(projectId: string, targetLabNumber: number): Promise<{ allowed: boolean, reason?: string }> {
        const project = await prisma.projects.findUnique({ where: { id: projectId } })
        if (!project) return { allowed: false, reason: 'Project not found' }

        if (targetLabNumber === 2) {
            if (project.score < 50) return { allowed: false, reason: 'Score global insuffisant (< 50/100)' }
        }

        return { allowed: true }
    }
}

// src/lib/workflow/definitions.ts

export interface LabStep {
    id: string
    title: string
    description: string
    expertId?: string // 'marcus', 'sarah', etc.
    type: 'EXPERT_SESSION' | 'GATE_CHECK' | 'SYNTHESIS'
}

export interface LabDefinition {
    id: string
    name: string
    minScore: number
    steps: LabStep[]
}

export const LAB_1_DISCOVERY: LabDefinition = {
    id: 'lab_1',
    name: 'Laboratoire 1 - Discovery',
    minScore: 0,
    steps: [
        {
            id: 'step_1_problem',
            title: 'Problem Deep Dive',
            description: 'Analyse approfondie du problème et identification de la cause racine.',
            expertId: 'marcus',
            type: 'EXPERT_SESSION'
        },
        {
            id: 'step_2_market',
            title: 'Market Validation',
            description: 'Validation de la taille du marché et analyse concurrentielle.',
            expertId: 'sarah',
            type: 'EXPERT_SESSION'
        },
        {
            id: 'step_3_customer',
            title: 'Customer Profiling',
            description: 'Définition du profil client idéal (ICP) et des segments.',
            expertId: 'elena',
            type: 'EXPERT_SESSION'
        },
        {
            id: 'step_4_gate',
            title: 'Pre-Gate Check',
            description: 'Vérification de la maturité du projet pour le passage au Lab 2.',
            type: 'GATE_CHECK'
        },
        {
            id: 'step_5_synthesis',
            title: 'Synthèse & Transition',
            description: 'Synthèse des apprentissages et décision Go/No-Go.',
            type: 'SYNTHESIS'
        }
    ]
}

export const LAB_2_STRUCTURATION: LabDefinition = {
    id: 'lab_2',
    name: 'Laboratoire 2 - Structuration',
    minScore: 50, // Gate condition
    steps: [
        {
            id: 'step_1_mvp',
            title: 'MVP Definition',
            description: 'Définition du périmètre fonctionnel du Minimum Viable Product.',
            expertId: 'david',
            type: 'EXPERT_SESSION'
        },
        {
            id: 'step_2_business',
            title: 'Business Model',
            description: 'Construction du modèle économique et des flux de revenus.',
            expertId: 'sophie',
            type: 'EXPERT_SESSION'
        },
        {
            id: 'step_3_finance',
            title: 'Financial Planning',
            description: 'Prévisions financières, budget et runway.',
            expertId: 'thomas',
            type: 'EXPERT_SESSION'
        },
        {
            id: 'step_4_gate',
            title: 'Pre-Launch Check',
            description: 'Vérification finale avant lancement.',
            type: 'GATE_CHECK'
        },
        {
            id: 'step_5_synthesis',
            title: 'Synthèse & Next Steps',
            description: 'Plan d\'action pour la phase suivante.',
            type: 'SYNTHESIS'
        }
    ]
}

export function getLabDefinition(labNumber: number): LabDefinition {
    return labNumber === 1 ? LAB_1_DISCOVERY : LAB_2_STRUCTURATION
}

