// src/hooks/use-workflow.ts
"use client";

import { useState, useEffect } from "react";

interface WorkflowState {
    workflow: {
        id: string;
        currentStep: number;
        totalSteps: number;
        status: string;
        labId: string;
        completedSteps: any[];
    };
    definition: {
        steps: {
            id: string;
            title: string;
            description: string;
            type: string;
        }[];
    };
}

export function useWorkflow(dossierId: string | undefined) {
    const [data, setData] = useState<WorkflowState | null>(null);
    const [isLoading, setIsLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);

    useEffect(() => {
        if (!dossierId) {
            setIsLoading(false);
            return;
        }

        async function fetchWorkflow() {
            try {
                const res = await fetch(`/api/workflow?dossierId=${dossierId}`);
                if (!res.ok) throw new Error('Failed to fetch workflow');
                const json = await res.json();

                if (json.workflow) {
                    setData(json);
                } else {
                    setData(null);
                }
            } catch (err) {
                console.error(err);
                setError('Could not load workflow');
            } finally {
                setIsLoading(false);
            }
        }

        fetchWorkflow();
    }, [dossierId]);

    // Function to force refresh (e.g. after XO action)
    const refresh = async () => {
        if (!dossierId) return;
        setIsLoading(true);
        try {
            const res = await fetch(`/api/workflow?dossierId=${dossierId}`);
            const json = await res.json();
            if (json.workflow) setData(json);
        } catch (err) {
            console.error(err);
        } finally {
            setIsLoading(false);
        }
    };

    return { ...data, isLoading, error, refresh };
}
